function PostCard({ post }) {
  return (
    <div className="post-card">

      <h2>{post.title}</h2>

      <p>{post.content}</p>

      <div className="card-footer">
        <span>👤 {post.author}</span>
        <span>❤️ {post.likes}</span>
        <span>💬 {post.comments}</span>
      </div>

    </div>
  );
}

export default PostCard;
